-- ============================================================================
-- Quiz Seed: Hebrews — Part 1 (Chapters 1–7)
-- 3 difficulties × 7 chapters = 112 total questions
--   kids:   3 per chapter  = 21
--   teens:  5 per chapter  = 35
--   adults: 8 per chapter  = 56
-- ============================================================================

-- ═══════════════ CHAPTERS 1–5 ═══════════════

-- ═══ Hebrews Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 1, 'kids', 1, 'How did God speak to people long ago?', 'Through the prophets', 'Through the radio', 'Through newspapers', 'Through letters in the mail', 'a', 'Hebrews 1:1 — "God, who at sundry times and in divers manners spake in time past unto the fathers by the prophets."'),
('Hebrews', 1, 'kids', 2, 'How does God speak to us now?', 'Through his Son, Jesus', 'Through the wind', 'Through animals', 'Through dreams only', 'a', 'Hebrews 1:2 — "Hath in these last days spoken unto us by his Son."'),
('Hebrews', 1, 'kids', 3, 'Is Jesus greater than the angels?', 'Yes, he is much greater than the angels', 'No, angels are greater', 'They are exactly the same', 'We don''t know', 'a', 'Hebrews 1:4 — "Being made so much better than the angels, as he hath by inheritance obtained a more excellent name than they."'),
-- Teens
('Hebrews', 1, 'teens', 1, 'What did God appoint his Son heir of?', 'All things — and by whom also he made the worlds', 'Only the land of Israel', 'Only the church', 'Only the heavens', 'a', 'Hebrews 1:2 — "Hath in these last days spoken unto us by his Son, whom he hath appointed heir of all things, by whom also he made the worlds."'),
('Hebrews', 1, 'teens', 2, 'What is the Son described as being in relation to God''s glory?', 'The brightness of his glory and the express image of his person', 'A faint reflection of God''s power', 'A distant shadow of God''s nature', 'A symbolic representation only', 'a', 'Hebrews 1:3 — "Who being the brightness of his glory, and the express image of his person."'),
('Hebrews', 1, 'teens', 3, 'What does the Son uphold?', 'All things by the word of his power', 'Only the church and believers', 'Only the nation of Israel', 'Only the heavenly realm', 'a', 'Hebrews 1:3 — "Upholding all things by the word of his power."'),
('Hebrews', 1, 'teens', 4, 'What did God say to the Son that he never said to any angel?', 'Thou art my Son, this day have I begotten thee', 'Thou art a mighty angel', 'Thou art a faithful servant', 'Thou art a great teacher', 'a', 'Hebrews 1:5 — "For unto which of the angels said he at any time, Thou art my Son, this day have I begotten thee?"'),
('Hebrews', 1, 'teens', 5, 'What are angels described as?', 'Ministering spirits, sent forth to minister for them who shall be heirs of salvation', 'Independent rulers of the heavens', 'Equal partners with God', 'Beings who do not serve humans', 'a', 'Hebrews 1:14 — "Are they not all ministering spirits, sent forth to minister for them who shall be heirs of salvation?"'),
-- Adults
('Hebrews', 1, 'adults', 1, 'How does the author describe God''s progressive revelation?', 'God spoke at sundry times and in divers manners in time past by the prophets, but in these last days hath spoken by his Son', 'God spoke once through Moses and never again', 'God speaks only through written Scripture', 'God speaks identically in every era', 'a', 'Hebrews 1:1-2 — "God, who at sundry times and in divers manners spake in time past unto the fathers by the prophets, Hath in these last days spoken unto us by his Son."'),
('Hebrews', 1, 'adults', 2, 'What did the Son do after purging our sins?', 'He sat down on the right hand of the Majesty on high', 'He returned to walk among men', 'He continued offering sacrifices', 'He went to prepare additional tabernacles', 'a', 'Hebrews 1:3 — "When he had by himself purged our sins, sat down on the right hand of the Majesty on high."'),
('Hebrews', 1, 'adults', 3, 'What does God say to the Son in verse 8?', 'Thy throne, O God, is for ever and ever: a sceptre of righteousness is the sceptre of thy kingdom', 'Thou art the greatest of the angels', 'Thy kingdom shall last a thousand years', 'Thou art the firstborn of creation', 'a', 'Hebrews 1:8 — "But unto the Son he saith, Thy throne, O God, is for ever and ever: a sceptre of righteousness is the sceptre of thy kingdom."'),
('Hebrews', 1, 'adults', 4, 'What does God say the Son has been anointed with above his fellows?', 'The oil of gladness — because he loved righteousness and hated iniquity', 'The oil of anointing from the temple', 'The water of baptism', 'The blood of the covenant', 'a', 'Hebrews 1:9 — "Thou hast loved righteousness, and hated iniquity; therefore God, even thy God, hath anointed thee with the oil of gladness above thy fellows."'),
('Hebrews', 1, 'adults', 5, 'What does God say about the Son and creation in verses 10-12?', 'Thou, Lord, in the beginning hast laid the foundation of the earth — they shall perish but thou remainest; they shall be changed but thou art the same', 'The Son was created along with the heavens', 'Creation is eternal and unchanging', 'The earth will never perish or change', 'a', 'Hebrews 1:10-12 — "Thou, Lord, in the beginning hast laid the foundation of the earth; and the heavens are the works of thine hands: They shall perish; but thou remainest... thou art the same, and thy years shall not fail."'),
('Hebrews', 1, 'adults', 6, 'What question does the author ask about the Son and angels in verse 13?', 'To which of the angels said he at any time, Sit on my right hand until I make thine enemies thy footstool?', 'Which angel was given dominion over creation?', 'Which angel was sent to redeem Israel?', 'Which angel is the mediator of the new covenant?', 'a', 'Hebrews 1:13 — "But to which of the angels said he at any time, Sit on my right hand, until I make thine enemies thy footstool?"'),
('Hebrews', 1, 'adults', 7, 'What Psalm does the author quote to address the Son as God?', 'Psalm 45:6-7 — "Thy throne, O God, is for ever and ever" — directly applying the title "God" to the Son', 'Psalm 23 — The Lord is my shepherd', 'Psalm 119 — Blessed are the undefiled', 'Psalm 51 — Create in me a clean heart', 'a', 'Hebrews 1:8-9 quotes Psalm 45:6-7, applying the title "O God" directly to the Son, affirming his deity.'),
('Hebrews', 1, 'adults', 8, 'What is the theological significance of the Son''s name being "more excellent" than the angels?', 'The Son''s superiority is by inheritance — he possesses divine nature and authority that no created being can share, establishing his deity and supremacy', 'The Son earned a better name through good behaviour', 'The name difference is merely ceremonial', 'Angels and the Son share equal nature but different titles', 'a', 'Hebrews 1:4 — "Being made so much better than the angels, as he hath by inheritance obtained a more excellent name than they." The inherited name signifies essential divine nature, not earned status.');

-- ═══ Hebrews Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 2, 'kids', 1, 'Why should we pay attention to what we have heard about Jesus?', 'So we don''t drift away from the truth', 'So we can become famous', 'So we can win a contest', 'So we can be smarter than everyone', 'a', 'Hebrews 2:1 — "Therefore we ought to give the more earnest heed to the things which we have heard, lest at any time we should let them slip."'),
('Hebrews', 2, 'kids', 2, 'What did Jesus taste for every person?', 'Death — he died for everyone', 'Good food at a feast', 'The water of a river', 'Honey from the promised land', 'a', 'Hebrews 2:9 — "That he by the grace of God should taste death for every man."'),
('Hebrews', 2, 'kids', 3, 'Is Jesus ashamed to call believers his brothers and sisters?', 'No, he is not ashamed to call them brethren', 'Yes, he is very ashamed', 'He doesn''t know who they are', 'He only calls the apostles his brethren', 'a', 'Hebrews 2:11 — "For which cause he is not ashamed to call them brethren."'),
-- Teens
('Hebrews', 2, 'teens', 1, 'What does the author call the salvation through Christ?', 'So great salvation — which began to be spoken by the Lord and was confirmed by them that heard him', 'A small and minor gift', 'An optional extra for believers', 'A temporary arrangement', 'a', 'Hebrews 2:3 — "How shall we escape, if we neglect so great salvation; which at the first began to be spoken by the Lord, and was confirmed unto us by them that heard him."'),
('Hebrews', 2, 'teens', 2, 'Why was Jesus made a little lower than the angels?', 'For the suffering of death — that he by the grace of God should taste death for every man', 'Because angels are more important', 'Because he was not truly God', 'Because he needed to learn from angels', 'a', 'Hebrews 2:9 — "But we see Jesus, who was made a little lower than the angels for the suffering of death, crowned with glory and honour; that he by the grace of God should taste death for every man."'),
('Hebrews', 2, 'teens', 3, 'What did Jesus destroy through his death?', 'Him that had the power of death, that is, the devil', 'The Roman empire', 'The temple in Jerusalem', 'The law of Moses', 'a', 'Hebrews 2:14 — "That through death he might destroy him that had the power of death, that is, the devil."'),
('Hebrews', 2, 'teens', 4, 'Who did Jesus come to help — angels or humans?', 'The seed of Abraham — he took not on him the nature of angels', 'The angels in heaven', 'Both equally', 'Neither humans nor angels', 'a', 'Hebrews 2:16 — "For verily he took not on him the nature of angels; but he took on him the seed of Abraham."'),
('Hebrews', 2, 'teens', 5, 'Why can Jesus help those who are tempted?', 'Because he himself hath suffered being tempted, he is able to succour them that are tempted', 'Because he has never experienced temptation', 'Because he uses angelic power to help', 'Because he only helps the strong', 'a', 'Hebrews 2:18 — "For in that he himself hath suffered being tempted, he is able to succour them that are tempted."'),
-- Adults
('Hebrews', 2, 'adults', 1, 'What rhetorical question does the author pose about neglecting salvation?', 'How shall we escape if we neglect so great salvation?', 'How shall we be rewarded for our good works?', 'How long must we wait for the second coming?', 'How can we improve the law of Moses?', 'a', 'Hebrews 2:3 — "How shall we escape, if we neglect so great salvation; which at the first began to be spoken by the Lord, and was confirmed unto us by them that heard him."'),
('Hebrews', 2, 'adults', 2, 'What title does the author give Jesus regarding salvation?', 'The captain of their salvation, made perfect through sufferings', 'The general of heaven''s armies', 'The king of earthly kingdoms', 'The architect of the universe', 'a', 'Hebrews 2:10 — "For it became him, for whom are all things, and by whom are all things, in bringing many sons unto glory, to make the captain of their salvation perfect through sufferings."'),
('Hebrews', 2, 'adults', 3, 'What does the author say about the sanctifier and those sanctified?', 'They are all of one, for which cause he is not ashamed to call them brethren', 'They are of entirely different natures', 'The sanctified can never approach the sanctifier', 'They have no relationship to each other', 'a', 'Hebrews 2:11 — "For both he that sanctifieth and they who are sanctified are all of one: for which cause he is not ashamed to call them brethren."'),
('Hebrews', 2, 'adults', 4, 'Why did Christ partake of flesh and blood?', 'That through death he might destroy him that had the power of death — the devil — and deliver them who through fear of death were all their lifetime subject to bondage', 'To enjoy the pleasures of human life', 'To demonstrate human frailty', 'To experience aging and natural death', 'a', 'Hebrews 2:14-15 — "Forasmuch then as the children are partakers of flesh and blood, he also himself likewise took part of the same; that through death he might destroy him that had the power of death, that is, the devil; And deliver them who through fear of death were all their lifetime subject to bondage."'),
('Hebrews', 2, 'adults', 5, 'What role is Jesus said to fulfil as a result of being made like his brethren?', 'A merciful and faithful high priest in things pertaining to God, to make reconciliation for the sins of the people', 'A political ruler over the nations', 'A military commander against Rome', 'A philosophical teacher of wisdom', 'a', 'Hebrews 2:17 — "Wherefore in all things it behoved him to be made like unto his brethren, that he might be a merciful and faithful high priest in things pertaining to God, to make reconciliation for the sins of the people."'),
('Hebrews', 2, 'adults', 6, 'What Psalm does the author quote about man being crowned with glory and honour?', 'Psalm 8:4-6 — "What is man, that thou art mindful of him?" applied to Christ''s incarnation and exaltation', 'Psalm 22 — My God, my God, why hast thou forsaken me', 'Psalm 110 — The LORD said unto my Lord', 'Psalm 2 — Thou art my Son', 'a', 'Hebrews 2:6-8 quotes Psalm 8:4-6: "What is man, that thou art mindful of him? or the son of man, that thou visitest him? Thou madest him a little lower than the angels; thou crownedst him with glory and honour."'),
('Hebrews', 2, 'adults', 7, 'What does the author say about "all things" being put under the Son?', 'We see not yet all things put under him, but we see Jesus crowned with glory and honour — the "not yet" shows eschatological tension', 'All things are already fully under his control visibly', 'Nothing has been put under him yet', 'Only spiritual things are under his authority', 'a', 'Hebrews 2:8-9 — "Thou hast put all things in subjection under his feet... But now we see not yet all things put under him. But we see Jesus, who was made a little lower than the angels for the suffering of death, crowned with glory and honour."'),
('Hebrews', 2, 'adults', 8, 'What does "made perfect through sufferings" mean regarding the captain of salvation?', 'Christ''s sufferings completed and qualified him as the perfect Saviour — not moral improvement but the completion of his redemptive work through his sacrifice', 'Christ was morally imperfect and needed suffering to be purified', 'Suffering is required for all believers to be saved', 'Christ''s divine nature was incomplete until the cross', 'a', 'Hebrews 2:10 — "To make the captain of their salvation perfect through sufferings." The Greek "teleiōsai" means to bring to completion — Christ''s saving work was completed through the cross.');

-- ═══ Hebrews Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 3, 'kids', 1, 'Who should we think about and focus on?', 'Jesus — the Apostle and High Priest of our profession', 'Only ourselves', 'Only rich and powerful people', 'Only our favourite teachers', 'a', 'Hebrews 3:1 — "Wherefore, holy brethren, partakers of the heavenly calling, consider the Apostle and High Priest of our profession, Christ Jesus."'),
('Hebrews', 3, 'kids', 2, 'Who was faithful in God''s house as a servant?', 'Moses', 'Aaron', 'Joshua', 'David', 'a', 'Hebrews 3:5 — "And Moses verily was faithful in all his house, as a servant."'),
('Hebrews', 3, 'kids', 3, 'What should we NOT do with our hearts?', 'Harden them — we should keep our hearts soft toward God', 'Make them brave', 'Fill them with love', 'Use them to worship God', 'a', 'Hebrews 3:8 — "Harden not your hearts, as in the provocation."'),
-- Teens
('Hebrews', 3, 'teens', 1, 'How is Christ counted worthy of more glory than Moses?', 'As the builder of a house hath more honour than the house — Moses was faithful in the house, but Christ built the house', 'Because Moses sinned and Christ did not', 'Because Christ lived longer than Moses', 'Because Christ performed greater miracles', 'a', 'Hebrews 3:3-4 — "For this man was counted worthy of more glory than Moses, inasmuch as he who hath builded the house hath more honour than the house. For every house is builded by some man; but he that built all things is God."'),
('Hebrews', 3, 'teens', 2, 'What role did Moses have in God''s house versus Christ?', 'Moses was faithful as a servant, but Christ as a Son over his own house', 'Moses was the owner and Christ was the builder', 'Moses was the high priest and Christ was the king', 'They held identical positions', 'a', 'Hebrews 3:5-6 — "And Moses verily was faithful in all his house, as a servant... But Christ as a son over his own house; whose house are we."'),
('Hebrews', 3, 'teens', 3, 'What happened when Israel hardened their hearts in the wilderness?', 'God swore in his wrath that they would not enter into his rest', 'God immediately forgave them', 'They conquered the promised land easily', 'Nothing happened as a result', 'a', 'Hebrews 3:11 — "So I sware in my wrath, They shall not enter into my rest."'),
('Hebrews', 3, 'teens', 4, 'What should believers do for each other daily?', 'Exhort one another daily, lest any be hardened through the deceitfulness of sin', 'Compete with one another for the best rewards', 'Ignore one another''s struggles', 'Judge one another''s worthiness', 'a', 'Hebrews 3:13 — "But exhort one another daily, while it is called To day; lest any of you be hardened through the deceitfulness of sin."'),
('Hebrews', 3, 'teens', 5, 'What kept the Israelites from entering the promised land?', 'Unbelief — they could not enter in because of unbelief', 'A physical wall around the land', 'A river too deep to cross', 'An army too strong to defeat', 'a', 'Hebrews 3:19 — "So we see that they could not enter in because of unbelief."'),
-- Adults
('Hebrews', 3, 'adults', 1, 'What two titles does the author give Christ in verse 1?', 'The Apostle and High Priest of our profession — the only time Christ is called "Apostle" in Scripture', 'Prophet and King', 'Shepherd and Bishop', 'Teacher and Healer', 'a', 'Hebrews 3:1 — "Wherefore, holy brethren, partakers of the heavenly calling, consider the Apostle and High Priest of our profession, Christ Jesus."'),
('Hebrews', 3, 'adults', 2, 'What does the author argue about Christ being the builder?', 'He that built all things is God — identifying Christ as the divine builder of God''s house, thus affirming his deity', 'Christ was merely a skilled craftsman', 'Moses was the true builder of God''s house', 'The house has no builder', 'a', 'Hebrews 3:4 — "For every house is builded by some man; but he that built all things is God."'),
('Hebrews', 3, 'adults', 3, 'What condition does the author attach to being Christ''s house?', 'If we hold fast the confidence and the rejoicing of the hope firm unto the end', 'If we perform all the ritual requirements of the law', 'If we achieve moral perfection in this life', 'If we earn enough merit through good works', 'a', 'Hebrews 3:6 — "But Christ as a son over his own house; whose house are we, if we hold fast the confidence and the rejoicing of the hope firm unto the end."'),
('Hebrews', 3, 'adults', 4, 'What Psalm does the author quote extensively about hardening hearts?', 'Psalm 95:7-11 — "To day if ye will hear his voice, Harden not your hearts, as in the provocation"', 'Psalm 23 — The Lord is my shepherd', 'Psalm 51 — Have mercy upon me', 'Psalm 119 — Thy word is a lamp', 'a', 'Hebrews 3:7-11 quotes Psalm 95:7-11 as the words of the Holy Ghost.'),
('Hebrews', 3, 'adults', 5, 'What does the author warn about an evil heart of unbelief?', 'Take heed lest there be in any of you an evil heart of unbelief in departing from the living God', 'Unbelief is a minor issue easily overlooked', 'Only certain people can have unbelief', 'Unbelief affects the mind but not the heart', 'a', 'Hebrews 3:12 — "Take heed, brethren, lest there be in any of you an evil heart of unbelief, in departing from the living God."'),
('Hebrews', 3, 'adults', 6, 'What does it mean to be "partakers of Christ"?', 'We are made partakers of Christ if we hold the beginning of our confidence stedfast unto the end', 'We automatically share in Christ regardless of perseverance', 'Only the apostles are partakers of Christ', 'Partaking of Christ is a future event only', 'a', 'Hebrews 3:14 — "For we are made partakers of Christ, if we hold the beginning of our confidence stedfast unto the end."'),
('Hebrews', 3, 'adults', 7, 'With whom was God grieved forty years?', 'With them that had sinned, whose carcases fell in the wilderness', 'With Moses and Aaron only', 'With the Canaanites', 'With the Egyptians who pursued them', 'a', 'Hebrews 3:17 — "But with whom was he grieved forty years? was it not with them that had sinned, whose carcases fell in the wilderness?"'),
('Hebrews', 3, 'adults', 8, 'What is the relationship between sin, unbelief, and disobedience in this chapter?', 'Sin leads to hardened hearts, unbelief causes departure from God, and disobedience prevents entering God''s rest — all three are interconnected', 'Sin and unbelief are unrelated concepts', 'Only outward disobedience matters, not the heart', 'Unbelief is acceptable if behaviour is correct', 'a', 'Hebrews 3:12-13,18-19 links an evil heart of unbelief, the deceitfulness of sin, and disobedience as interconnected causes that prevented Israel from entering rest.');

-- ═══ Hebrews Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 4, 'kids', 1, 'What is the word of God described as?', 'Quick (living) and powerful, and sharper than any twoedged sword', 'A dusty old book', 'A quiet whisper no one can hear', 'A confusing riddle', 'a', 'Hebrews 4:12 — "For the word of God is quick, and powerful, and sharper than any twoedged sword."'),
('Hebrews', 4, 'kids', 2, 'Who is our great high priest in heaven?', 'Jesus, the Son of God', 'Moses', 'Aaron', 'Abraham', 'a', 'Hebrews 4:14 — "Seeing then that we have a great high priest, that is passed into the heavens, Jesus the Son of God."'),
('Hebrews', 4, 'kids', 3, 'How can we come to God for help?', 'Boldly — we can come boldly to the throne of grace', 'Only with fear and trembling', 'Only through a priest on earth', 'Only on special holy days', 'a', 'Hebrews 4:16 — "Let us therefore come boldly unto the throne of grace."'),
-- Teens
('Hebrews', 4, 'teens', 1, 'What promise remains for the people of God?', 'A rest — there remaineth therefore a rest to the people of God', 'A palace in Jerusalem', 'An earthly kingdom', 'A treasure of gold and silver', 'a', 'Hebrews 4:9 — "There remaineth therefore a rest to the people of God."'),
('Hebrews', 4, 'teens', 2, 'What does the word of God pierce and divide?', 'It pierces even to the dividing asunder of soul and spirit, and of the joints and marrow, and is a discerner of the thoughts and intents of the heart', 'Only the written text of the law', 'Only the physical world around us', 'Only the outward actions of people', 'a', 'Hebrews 4:12 — "Piercing even to the dividing asunder of soul and spirit, and of the joints and marrow, and is a discerner of the thoughts and intents of the heart."'),
('Hebrews', 4, 'teens', 3, 'Can our high priest sympathize with our weaknesses?', 'Yes — he was in all points tempted like as we are, yet without sin', 'No, he has never experienced human weakness', 'Only with some of our weaknesses', 'He understands but chooses not to help', 'a', 'Hebrews 4:15 — "For we have not an high priest which cannot be touched with the feeling of our infirmities; but was in all points tempted like as we are, yet without sin."'),
('Hebrews', 4, 'teens', 4, 'What do we find when we come boldly to the throne of grace?', 'Mercy and grace to help in time of need', 'Punishment for our sins', 'A list of our failures', 'Rejection and disappointment', 'a', 'Hebrews 4:16 — "Let us therefore come boldly unto the throne of grace, that we may obtain mercy, and find grace to help in time of need."'),
('Hebrews', 4, 'teens', 5, 'Why did the gospel not profit the Israelites who heard it?', 'Because it was not mixed with faith in them that heard it', 'Because Moses didn''t explain it clearly', 'Because the desert was too hot for worship', 'Because they were too tired from travelling', 'a', 'Hebrews 4:2 — "For unto us was the gospel preached, as well as unto them: but the word preached did not profit them, not being mixed with faith in them that heard it."'),
-- Adults
('Hebrews', 4, 'adults', 1, 'What does the author mean by God''s rest that remains?', 'A spiritual Sabbath rest for the people of God — he that is entered into his rest hath ceased from his own works as God did from his', 'Only the physical land of Canaan', 'Only the weekly Sabbath observance', 'Only the rest experienced after death', 'a', 'Hebrews 4:9-10 — "There remaineth therefore a rest to the people of God. For he that is entered into his rest, he also hath ceased from his own works, as God did from his."'),
('Hebrews', 4, 'adults', 2, 'What four attributes does the author give to the word of God?', 'Quick (living), powerful, sharper than any twoedged sword, and a discerner of the thoughts and intents of the heart', 'Ancient, complex, difficult, and mysterious', 'Simple, clear, brief, and historical', 'Poetic, musical, artistic, and cultural', 'a', 'Hebrews 4:12 — "For the word of God is quick, and powerful, and sharper than any twoedged sword, piercing even to the dividing asunder of soul and spirit... and is a discerner of the thoughts and intents of the heart."'),
('Hebrews', 4, 'adults', 3, 'What does "neither is there any creature that is not manifest in his sight" mean?', 'All things are naked and opened unto the eyes of him with whom we have to do — complete divine omniscience leaving nothing hidden', 'Some things are hidden from God', 'God only sees outward actions', 'God chooses not to see certain things', 'a', 'Hebrews 4:13 — "Neither is there any creature that is not manifest in his sight: but all things are naked and opened unto the eyes of him with whom we have to do."'),
('Hebrews', 4, 'adults', 4, 'What does "passed into the heavens" mean regarding Jesus?', 'Jesus has passed through the heavens into God''s very presence — paralleling the high priest entering the Holy of Holies, but into the true heavenly sanctuary', 'Jesus merely ascended to the clouds', 'Jesus went to one of the created heavens', 'Jesus went to a physical location in the sky', 'a', 'Hebrews 4:14 — "Seeing then that we have a great high priest, that is passed into the heavens, Jesus the Son of God, let us hold fast our profession."'),
('Hebrews', 4, 'adults', 5, 'What is the significance of Christ being tempted "in all points" yet without sin?', 'Christ''s sinless perfection through genuine temptation qualifies him uniquely as our sympathetic high priest who fully understands human weakness', 'His temptations were not real because he was God', 'He was only tempted in a few specific areas', 'His sinlessness means he cannot understand temptation', 'a', 'Hebrews 4:15 — "For we have not an high priest which cannot be touched with the feeling of our infirmities; but was in all points tempted like as we are, yet without sin."'),
('Hebrews', 4, 'adults', 6, 'How does the author use Joshua to argue for a future rest?', 'If Joshua had given them rest, God would not afterward have spoken of another day — therefore a rest yet remains', 'Joshua fulfilled all the promises of rest', 'Joshua''s rest was identical to God''s rest', 'Joshua never entered the promised land', 'a', 'Hebrews 4:8 — "For if Jesus [Joshua] had given them rest, then would he not afterward have spoken of another day."'),
('Hebrews', 4, 'adults', 7, 'What exhortation does the author give about entering God''s rest?', 'Let us labour therefore to enter into that rest, lest any man fall after the same example of unbelief', 'Let us rest from all effort immediately', 'Let us wait passively for rest to come', 'Let us earn our rest through perfect obedience', 'a', 'Hebrews 4:11 — "Let us labour therefore to enter into that rest, lest any man fall after the same example of unbelief."'),
('Hebrews', 4, 'adults', 8, 'What does the phrase "the throne of grace" imply?', 'God''s throne is characterized by grace rather than judgment for those who approach through Christ — it is a place of mercy and timely help', 'The throne is made of a graceful material', 'Only certain people may approach it', 'The throne dispenses both grace and wrath equally', 'a', 'Hebrews 4:16 — "Let us therefore come boldly unto the throne of grace, that we may obtain mercy, and find grace to help in time of need."');

-- ═══ Hebrews Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 5, 'kids', 1, 'What kind of priest is Jesus called?', 'A priest forever after the order of Melchisedec', 'A priest of the temple in Jerusalem', 'A Levitical priest', 'A priest of Aaron', 'a', 'Hebrews 5:6 — "Thou art a priest for ever after the order of Melchisedec."'),
('Hebrews', 5, 'kids', 2, 'Did Jesus learn to obey even though he is God''s Son?', 'Yes, he learned obedience by the things which he suffered', 'No, he never had to learn anything', 'He only pretended to learn', 'He learned from the angels', 'a', 'Hebrews 5:8 — "Though he were a Son, yet learned he obedience by the things which he suffered."'),
('Hebrews', 5, 'kids', 3, 'What is the difference between milk and strong meat (solid food)?', 'Milk is for beginners and strong meat is for those who are grown up in faith', 'Milk is better than meat', 'They are exactly the same', 'Strong meat is for babies', 'a', 'Hebrews 5:12-14 — "Ye have need that one teach you again... and are become such as have need of milk, and not of strong meat."'),
-- Teens
('Hebrews', 5, 'teens', 1, 'Where does a high priest come from?', 'From among men — taken from among men and ordained for men in things pertaining to God', 'From among the angels', 'From a special divine creation', 'From a royal family only', 'a', 'Hebrews 5:1 — "For every high priest taken from among men is ordained for men in things pertaining to God, that he may offer both gifts and sacrifices for sins."'),
('Hebrews', 5, 'teens', 2, 'Can a high priest choose this honour for himself?', 'No man taketh this honour unto himself, but he that is called of God as was Aaron', 'Yes, anyone who wants to can be high priest', 'Only the firstborn son can choose it', 'The people vote for who they want', 'a', 'Hebrews 5:4 — "And no man taketh this honour unto himself, but he that is called of God, as was Aaron."'),
('Hebrews', 5, 'teens', 3, 'What did Jesus offer up with strong crying and tears?', 'Prayers and supplications unto him that was able to save him from death, and was heard in that he feared', 'Animal sacrifices in the temple', 'Gold and silver offerings', 'Songs of praise and worship', 'a', 'Hebrews 5:7 — "Who in the days of his flesh, when he had offered up prayers and supplications with strong crying and tears unto him that was able to save him from death, and was heard in that he feared."'),
('Hebrews', 5, 'teens', 4, 'What did Jesus become after being made perfect?', 'The author of eternal salvation unto all them that obey him', 'The ruler of all earthly kingdoms', 'The commander of the angelic armies', 'The judge who condemns all sinners', 'a', 'Hebrews 5:9 — "And being made perfect, he became the author of eternal salvation unto all them that obey him."'),
('Hebrews', 5, 'teens', 5, 'Why does the author scold the readers?', 'By this time they ought to be teachers, but they need to be taught the first principles again — they need milk, not strong meat', 'They were teaching false doctrine', 'They had become too advanced', 'They were giving too much money', 'a', 'Hebrews 5:12 — "For when for the time ye ought to be teachers, ye have need that one teach you again which be the first principles of the oracles of God; and are become such as have need of milk, and not of strong meat."'),
-- Adults
('Hebrews', 5, 'adults', 1, 'What two qualities must a high priest have regarding sinners?', 'He must be able to have compassion on the ignorant and on them that are out of the way, for he himself also is compassed with infirmity', 'Perfect holiness and complete detachment', 'Stern judgment and strict discipline', 'Wealth and political influence', 'a', 'Hebrews 5:2 — "Who can have compassion on the ignorant, and on them that are out of the way; for that he himself also is compassed with infirmity."'),
('Hebrews', 5, 'adults', 2, 'How does Christ''s appointment as high priest parallel Aaron''s?', 'Christ glorified not himself to be made an high priest — God said "Thou art my Son" and "Thou art a priest for ever after the order of Melchisedec"', 'Christ appointed himself based on his divine nature', 'Christ was appointed by the Sanhedrin', 'Christ inherited the position from his earthly father', 'a', 'Hebrews 5:5-6 — "So also Christ glorified not himself to be made an high priest; but he that said unto him, Thou art my Son, to day have I begotten thee. As he saith also in another place, Thou art a priest for ever after the order of Melchisedec."'),
('Hebrews', 5, 'adults', 3, 'What does "learned he obedience by the things which he suffered" mean?', 'Though eternally the Son, Christ experientially learned what obedience costs through his human suffering — not that he was previously disobedient', 'He was disobedient before and suffering taught him to obey', 'Suffering is the only way to learn anything', 'His divine nature needed to be improved', 'a', 'Hebrews 5:8 — "Though he were a Son, yet learned he obedience by the things which he suffered." This refers to experiential knowledge of obedience through suffering, not moral correction.'),
('Hebrews', 5, 'adults', 4, 'What does it mean that Christ was "made perfect"?', 'Being made perfect (teleiōtheis) — brought to completion or full qualification as the perfect Saviour through the completion of his earthly suffering and obedience', 'He was morally imperfect and needed to improve', 'He lacked divine attributes that suffering provided', 'He was already perfect and nothing changed', 'a', 'Hebrews 5:9 — "And being made perfect, he became the author of eternal salvation unto all them that obey him." The word implies completion of his saving work, not moral improvement.'),
('Hebrews', 5, 'adults', 5, 'What does the author mean by "strong meat belongeth to them that are of full age"?', 'Mature believers who by reason of use have their senses exercised to discern both good and evil', 'Only elderly Christians can understand deep doctrine', 'Strong meat refers to literal food restrictions', 'Full age means exactly thirty years old', 'a', 'Hebrews 5:14 — "But strong meat belongeth to them that are of full age, even those who by reason of use have their senses exercised to discern both good and evil."'),
('Hebrews', 5, 'adults', 6, 'What is significant about Christ being "called of God an high priest after the order of Melchisedec"?', 'It establishes a priesthood that precedes and supersedes the Levitical order — not based on tribal descent but on divine appointment and eternal duration', 'Melchisedec was Aaron''s predecessor in the same priestly line', 'This is merely a metaphorical comparison', 'Melchisedec was actually an angel, not a human', 'a', 'Hebrews 5:10 — "Called of God an high priest after the order of Melchisedec." This introduces the argument developed in chapter 7.'),
('Hebrews', 5, 'adults', 7, 'What rebuke does the author give about their spiritual condition?', 'They are dull of hearing — by this time they should be teachers but instead need to be taught the first principles again', 'They are too advanced for their own good', 'They study too much and need to rest', 'They are perfectly mature in their faith', 'a', 'Hebrews 5:11-12 — "Of whom we have many things to say, and hard to be uttered, seeing ye are dull of hearing. For when for the time ye ought to be teachers, ye have need that one teach you again which be the first principles of the oracles of God."'),
('Hebrews', 5, 'adults', 8, 'What is the "first principles of the oracles of God" that the readers need again?', 'The elementary teachings of God''s word — they are unskilful in the word of righteousness, like babes needing milk', 'Advanced theological debates', 'Secret knowledge for the elite', 'The Greek philosophical foundations', 'a', 'Hebrews 5:12-13 — "Ye have need that one teach you again which be the first principles of the oracles of God; and are become such as have need of milk, and not of strong meat. For every one that useth milk is unskilful in the word of righteousness: for he is a babe."');

-- ═══════════════ CHAPTERS 6–7 ═══════════════

-- ═══ Hebrews Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 6, 'kids', 1, 'What does the author want the readers to do?', 'Go on unto perfection (grow up in their faith)', 'Stay as babies in their faith', 'Stop learning about God', 'Go back to the very beginning again', 'a', 'Hebrews 6:1 — "Therefore leaving the principles of the doctrine of Christ, let us go on unto perfection."'),
('Hebrews', 6, 'kids', 2, 'Does God forget the good things we do for him?', 'No, God is not unrighteous to forget your work and labour of love', 'Yes, God forgets everything we do', 'He only remembers the bad things', 'He only remembers some things', 'a', 'Hebrews 6:10 — "For God is not unrighteous to forget your work and labour of love, which ye have shewed toward his name."'),
('Hebrews', 6, 'kids', 3, 'What is our hope compared to?', 'An anchor of the soul, both sure and stedfast', 'A kite flying in the wind', 'A leaf blown by the breeze', 'A ship without a rudder', 'a', 'Hebrews 6:19 — "Which hope we have as an anchor of the soul, both sure and stedfast."'),
-- Teens
('Hebrews', 6, 'teens', 1, 'What six foundation teachings does the author list?', 'Repentance from dead works, faith toward God, doctrine of baptisms, laying on of hands, resurrection of the dead, eternal judgment', 'Love, joy, peace, patience, kindness, goodness', 'Prayer, fasting, giving, worship, fellowship, study', 'Creation, fall, flood, exodus, exile, return', 'a', 'Hebrews 6:1-2 — "Not laying again the foundation of repentance from dead works, and of faith toward God, Of the doctrine of baptisms, and of laying on of hands, and of resurrection of the dead, and of eternal judgment."'),
('Hebrews', 6, 'teens', 2, 'What does the author compare to land that receives rain and brings forth herbs?', 'Those who receive God''s blessings and produce good fruit — they receive blessing from God', 'Those who study philosophy', 'Those who travel to many places', 'Those who accumulate wealth', 'a', 'Hebrews 6:7 — "For the earth which drinketh in the rain that cometh oft upon it, and bringeth forth herbs meet for them by whom it is dressed, receiveth blessing from God."'),
('Hebrews', 6, 'teens', 3, 'What does the author want each believer to show?', 'The same diligence to the full assurance of hope unto the end', 'Wealth and prosperity', 'Great speaking ability', 'Perfect knowledge of all Scripture', 'a', 'Hebrews 6:11 — "And we desire that every one of you do shew the same diligence to the full assurance of hope unto the end."'),
('Hebrews', 6, 'teens', 4, 'What two immutable (unchangeable) things give us strong consolation?', 'God''s promise and God''s oath — it is impossible for God to lie', 'Our own strength and our own wisdom', 'The law and the prophets', 'The temple and the priesthood', 'a', 'Hebrews 6:17-18 — "God, willing more abundantly to shew unto the heirs of promise the immutability of his counsel, confirmed it by an oath: That by two immutable things, in which it was impossible for God to lie, we might have a strong consolation."'),
('Hebrews', 6, 'teens', 5, 'Where does our anchor of hope enter?', 'Within the veil — where Jesus as our forerunner has entered for us, a high priest after the order of Melchisedec', 'Into the depths of the ocean', 'Into the foundation of the earth', 'Into the walls of the temple', 'a', 'Hebrews 6:19-20 — "Which hope we have as an anchor of the soul, both sure and stedfast, and which entereth into that within the veil; Whither the forerunner is for us entered, even Jesus, made an high priest for ever after the order of Melchisedec."'),
-- Adults
('Hebrews', 6, 'adults', 1, 'What does the author say is impossible regarding those who "fall away" in verses 4-6?', 'It is impossible to renew them again unto repentance if they were once enlightened, tasted the heavenly gift, were made partakers of the Holy Ghost, tasted the good word and powers of the world to come, and then fell away', 'It is impossible to sin after being saved', 'It is impossible to understand the gospel without a teacher', 'It is impossible to lose any spiritual gift once received', 'a', 'Hebrews 6:4-6 — "For it is impossible for those who were once enlightened, and have tasted of the heavenly gift, and were made partakers of the Holy Ghost, And have tasted the good word of God, and the powers of the world to come, If they shall fall away, to renew them again unto repentance."'),
('Hebrews', 6, 'adults', 2, 'Why is it impossible to renew such people to repentance?', 'They crucify to themselves the Son of God afresh and put him to an open shame', 'Because God is not powerful enough', 'Because the cross has limited effectiveness', 'Because salvation can only be offered once', 'a', 'Hebrews 6:6 — "If they shall fall away, to renew them again unto repentance; seeing they crucify to themselves the Son of God afresh, and put him to an open shame."'),
('Hebrews', 6, 'adults', 3, 'What agricultural metaphor does the author use for apostasy?', 'Land that beareth thorns and briers is rejected, nigh unto cursing, whose end is to be burned — contrasted with land that brings forth herbs and receives blessing', 'A vine that produces sour grapes', 'A tree that bears no leaves', 'A field with no seeds planted', 'a', 'Hebrews 6:7-8 — "For the earth which drinketh in the rain... and bringeth forth herbs... receiveth blessing from God: But that which beareth thorns and briers is rejected, and is nigh unto cursing; whose end is to be burned."'),
('Hebrews', 6, 'adults', 4, 'What is the author persuaded of regarding his readers despite the severe warning?', 'Better things of them, and things that accompany salvation — though he thus speaks', 'That they have already fallen away', 'That they are beyond hope', 'That most of them are unbelievers', 'a', 'Hebrews 6:9 — "But, beloved, we are persuaded better things of you, and things that accompany salvation, though we thus speak."'),
('Hebrews', 6, 'adults', 5, 'What example does the author give of patient endurance?', 'Abraham — who after he had patiently endured, obtained the promise', 'Moses — who led Israel through the wilderness', 'David — who waited to become king', 'Job — who endured suffering', 'a', 'Hebrews 6:15 — "And so, after he had patiently endured, he obtained the promise."'),
('Hebrews', 6, 'adults', 6, 'Why did God confirm his promise with an oath?', 'Willing more abundantly to shew unto the heirs of promise the immutability of his counsel — since he could swear by no greater, he sware by himself', 'Because his word alone was not trustworthy', 'Because Abraham demanded an oath', 'Because oaths were required by Jewish law', 'a', 'Hebrews 6:13,17 — "For when God made promise to Abraham, because he could swear by no greater, he sware by himself... God, willing more abundantly to shew unto the heirs of promise the immutability of his counsel, confirmed it by an oath."'),
('Hebrews', 6, 'adults', 7, 'What does calling Jesus a "forerunner" who entered within the veil signify?', 'Unlike the Levitical high priest who entered alone, Jesus entered as a forerunner — implying that others will follow him into God''s presence', 'Jesus entered but no one else can follow', 'The veil still separates God from man', 'Jesus entered a physical temple in heaven', 'a', 'Hebrews 6:20 — "Whither the forerunner is for us entered, even Jesus, made an high priest for ever after the order of Melchisedec." The term "forerunner" implies others will follow.'),
('Hebrews', 6, 'adults', 8, 'What does the "anchor of the soul" represent theologically?', 'Christian hope grounded in God''s promise and oath, entering the heavenly sanctuary where Christ intercedes — providing absolute security and certainty despite life''s storms', 'A physical anchor used in worship', 'A metaphor for earthly stability and wealth', 'A symbol of remaining fixed in one location', 'a', 'Hebrews 6:19 — "Which hope we have as an anchor of the soul, both sure and stedfast, and which entereth into that within the veil." The anchor connects the believer to the heavenly sanctuary.');

-- ═══ Hebrews Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 7, 'kids', 1, 'Who was Melchisedec?', 'King of Salem and priest of the most high God', 'A Roman soldier', 'An Egyptian pharaoh', 'A fisherman from Galilee', 'a', 'Hebrews 7:1 — "For this Melchisedec, king of Salem, priest of the most high God."'),
('Hebrews', 7, 'kids', 2, 'What great man gave a tenth of everything to Melchisedec?', 'Abraham', 'Moses', 'David', 'Solomon', 'a', 'Hebrews 7:2 — "To whom also Abraham gave a tenth part of all."'),
('Hebrews', 7, 'kids', 3, 'Does Jesus ever stop being our priest?', 'No, he continues forever as our priest', 'Yes, he stopped when he went to heaven', 'Yes, he passed it to someone else', 'He was never a priest', 'a', 'Hebrews 7:24 — "But this man, because he continueth ever, hath an unchangeable priesthood."'),
-- Teens
('Hebrews', 7, 'teens', 1, 'What does the name Melchisedec mean?', 'King of righteousness — and King of Salem means King of peace', 'King of war and conquest', 'King of wisdom and learning', 'King of wealth and power', 'a', 'Hebrews 7:2 — "First being by interpretation King of righteousness, and after that also King of Salem, which is, King of peace."'),
('Hebrews', 7, 'teens', 2, 'How is Melchisedec described in terms of genealogy?', 'Without father, without mother, without descent, having neither beginning of days nor end of life, made like unto the Son of God', 'Son of Aaron from the tribe of Levi', 'Son of Abraham from the tribe of Judah', 'A descendant of Adam through Seth', 'a', 'Hebrews 7:3 — "Without father, without mother, without descent, having neither beginning of days, nor end of life; but made like unto the Son of God; abideth a priest continually."'),
('Hebrews', 7, 'teens', 3, 'Why is the Melchisedec priesthood better than the Levitical?', 'If perfection were by the Levitical priesthood, why was there need for another priest after the order of Melchisedec?', 'The Levitical priests performed more sacrifices', 'The Levitical priests were better educated', 'The Levitical priesthood was newer and more relevant', 'a', 'Hebrews 7:11 — "If therefore perfection were by the Levitical priesthood... what further need was there that another priest should rise after the order of Melchisedec, and not be called after the order of Aaron?"'),
('Hebrews', 7, 'teens', 4, 'What does Jesus save us through because he lives forever?', 'He is able to save them to the uttermost that come unto God by him, seeing he ever liveth to make intercession for them', 'He saves only those who perform enough good works', 'He saves only the Jewish people', 'He saves only those who keep the law perfectly', 'a', 'Hebrews 7:25 — "Wherefore he is able also to save them to the uttermost that come unto God by him, seeing he ever liveth to make intercession for them."'),
('Hebrews', 7, 'teens', 5, 'What kind of high priest do we need?', 'One who is holy, harmless, undefiled, separate from sinners, and made higher than the heavens', 'One who is wealthy and powerful', 'One who is experienced in worldly affairs', 'One who is politically connected', 'a', 'Hebrews 7:26 — "For such an high priest became us, who is holy, harmless, undefiled, separate from sinners, and made higher than the heavens."'),
-- Adults
('Hebrews', 7, 'adults', 1, 'What argument does the author make about Abraham paying tithes to Melchisedec?', 'The less is blessed of the better — since Abraham (and Levi in his loins) paid tithes to Melchisedec, the Melchisedec priesthood is superior to the Levitical', 'Abraham was forced to pay under duress', 'The tithes were a temporary cultural custom', 'Melchisedec was Abraham''s servant', 'a', 'Hebrews 7:4,7,9-10 — "Now consider how great this man was, unto whom even the patriarch Abraham gave the tenth of the spoils... without all contradiction the less is blessed of the better... Levi also, who receiveth tithes, payed tithes in Abraham."'),
('Hebrews', 7, 'adults', 2, 'What change does the new priesthood necessitate?', 'For the priesthood being changed, there is made of necessity a change also of the law', 'The law remains exactly the same', 'Only the sacrifices change, not the law', 'The priesthood and law are unrelated', 'a', 'Hebrews 7:12 — "For the priesthood being changed, there is made of necessity a change also of the law."'),
('Hebrews', 7, 'adults', 3, 'How is Christ''s priesthood different from the Levitical?', 'Not after the law of a carnal commandment, but after the power of an endless life', 'Based on tribal descent from Levi', 'Temporary and transferred to successors', 'Requiring daily animal sacrifices', 'a', 'Hebrews 7:16 — "Who is made, not after the law of a carnal commandment, but after the power of an endless life."'),
('Hebrews', 7, 'adults', 4, 'What does the author say the law made nothing perfect?', 'The law made nothing perfect, but the bringing in of a better hope did, by the which we draw nigh unto God', 'The law achieved complete perfection', 'The law was the final revelation of God', 'The law and the new covenant are identical', 'a', 'Hebrews 7:19 — "For the law made nothing perfect, but the bringing in of a better hope did; by the which we draw nigh unto God."'),
('Hebrews', 7, 'adults', 5, 'What makes Jesus the surety of a better testament?', 'He was made priest with an oath — the Lord sware and will not repent, Thou art a priest for ever — making him surety of a better testament', 'He provided a large financial guarantee', 'He signed a written agreement', 'He was approved by the Sanhedrin', 'a', 'Hebrews 7:21-22 — "The Lord sware and will not repent, Thou art a priest for ever after the order of Melchisedec: By so much was Jesus made a surety of a better testament."'),
('Hebrews', 7, 'adults', 6, 'Why is Christ''s priesthood "unchangeable"?', 'Because he continueth ever — the Greek "aparabatos" means untransferable, it cannot be passed to a successor because he lives forever', 'Because no one wants to replace him', 'Because the church voted to keep him', 'Because the law forbids any change', 'a', 'Hebrews 7:24 — "But this man, because he continueth ever, hath an unchangeable priesthood." The word "aparabatos" means a priesthood that does not pass to another.'),
('Hebrews', 7, 'adults', 7, 'What does "save them to the uttermost" mean?', 'Completely, perfectly, and eternally — Christ''s intercession is perpetual and his salvation is total for all who come to God through him', 'Save only the most deserving believers', 'Save temporarily until the next sacrifice', 'Save partially, requiring additional works', 'a', 'Hebrews 7:25 — "Wherefore he is able also to save them to the uttermost that come unto God by him, seeing he ever liveth to make intercession for them."'),
('Hebrews', 7, 'adults', 8, 'How does Christ''s once-for-all sacrifice differ from the Levitical priests''?', 'He needeth not daily to offer up sacrifice first for his own sins then for the people — he did this once when he offered up himself, being sinless', 'He offers sacrifices more frequently than they did', 'He offers the same type of animal sacrifices', 'He must repeat his sacrifice periodically', 'a', 'Hebrews 7:27 — "Who needeth not daily, as those high priests, to offer up sacrifice, first for his own sins, and then for the people''s: for this he did once, when he offered up himself."');
